mapper.select:
/* 수업 기본 정보 (회원/스태프 없어도 반드시 포함) */ SELECT ts.seq AS timeSlotSeq, CONCAT(ts.name, ' ', ts.days_of_week, ' (', DATE_FORMAT(ts.start_time, '%H:%i'), ' ~ ', DATE_FORMAT(ts.end_time, '%H:%i'), ')') AS slotName, c.seq AS classSeq, c.name AS className, c.capacity AS capacity, NULL AS memberSeq, NULL AS name, NULL AS phoneNumber, FALSE AS staff, FALSE AS postponed, NULL AS status FROM complex_classes c JOIN class_time_slots ts ON ts.seq = c.time_slot_seq WHERE c.branch_seq = #{branchSeq} AND c.seq NOT IN ( SELECT DISTINCT c2.seq FROM complex_classes c2 LEFT JOIN complex_members s2 ON s2.seq = c2.staff_seq LEFT JOIN complex_member_class_mapping mcm2 ON mcm2.class_seq = c2.seq WHERE c2.branch_seq = #{branchSeq} AND (s2.seq IS NOT NULL OR mcm2.member_seq IS NOT NULL) )
UNION ALL
/* 스태프 */ SELECT ts.seq AS timeSlotSeq, CONCAT(ts.name, ' ', ts.days_of_week, ' (', DATE_FORMAT(ts.start_time, '%H:%i'), ' ~ ', DATE_FORMAT(ts.end_time, '%H:%i'), ')') AS slotName, c.seq AS classSeq, c.name AS className, c.capacity AS capacity, s.seq AS memberSeq, s.name AS name, s.phone_number AS phoneNumber, TRUE AS staff, FALSE AS postponed, CASE a.status WHEN '출석' THEN 'O' WHEN '결석' THEN 'X' ELSE '' END AS status FROM complex_classes c JOIN class_time_slots ts ON ts.seq = c.time_slot_seq JOIN complex_members s ON s.seq = c.staff_seq LEFT JOIN complex_member_attendance a ON a.member_seq = s.seq AND a.class_seq = c.seq AND a.attendance_date = #{today} WHERE c.branch_seq = #{branchSeq}
UNION ALL
/* 회원 */ SELECT ts.seq AS timeSlotSeq, CONCAT(ts.name, ' ', ts.days_of_week, ' (', DATE_FORMAT(ts.start_time, '%H:%i'), ' ~ ', DATE_FORMAT(ts.end_time, '%H:%i'), ')') AS slotName, c.seq AS classSeq, c.name AS className, c.capacity AS capacity, m.seq AS memberSeq, m.name AS name, m.phone_number AS phoneNumber, FALSE AS staff, CASE WHEN mm.status = '연기' THEN TRUE ELSE FALSE END AS postponed, CASE WHEN mm.status = '연기' THEN '△' WHEN a.status = '출석' THEN 'O' WHEN a.status = '결석' THEN 'X' ELSE '' END AS status FROM complex_member_class_mapping mcm JOIN complex_classes c ON c.seq = mcm.class_seq JOIN class_time_slots ts ON ts.seq = c.time_slot_seq JOIN complex_members m ON m.seq = mcm.member_seq LEFT JOIN complex_member_memberships mm ON mm.member_seq = m.seq AND mm.status IN ('활성', '연기') AND mm.internal = FALSE LEFT JOIN complex_member_attendance a ON a.member_seq = m.seq AND a.class_seq = c.seq AND a.attendance_date = #{today} WHERE c.branch_seq = #{branchSeq}
ORDER BY timeSlotSeq, classSeq, staff DESC, name

/* 수업 기본 정보 (회원/스태프 없어도 반드시 포함) */ SELECT c.seq AS classSeq, c.name AS className, c.capacity AS capacity, NULL AS memberSeq, NULL AS name, NULL AS phoneNumber, FALSE AS staff, FALSE AS postponed, NULL AS status, NULL AS level, NULL AS info, NULL AS joinDate, NULL AS expiryDate, NULL AS totalCount, NULL AS usedCount, NULL AS membershipName FROM complex_classes c WHERE c.branch_seq = #{branchSeq} AND c.time_slot_seq = #{slotSeq} AND c.seq NOT IN ( SELECT DISTINCT c2.seq FROM complex_classes c2 LEFT JOIN complex_members s2 ON s2.seq = c2.staff_seq LEFT JOIN complex_member_class_mapping mcm2 ON mcm2.class_seq = c2.seq WHERE c2.branch_seq = #{branchSeq} AND c2.time_slot_seq = #{slotSeq} AND (s2.seq IS NOT NULL OR mcm2.member_seq IS NOT NULL) )
UNION ALL
/* 스태프 */ SELECT c.seq AS classSeq, c.name AS className, c.capacity AS capacity, s.seq AS memberSeq, s.name AS name, s.phone_number AS phoneNumber, TRUE AS staff, FALSE AS postponed, '' AS status, NULL AS level, NULL AS info, NULL AS joinDate, NULL AS expiryDate, NULL AS totalCount, NULL AS usedCount, NULL AS membershipName FROM complex_classes c JOIN class_time_slots ts ON ts.seq = c.time_slot_seq JOIN complex_members s ON s.seq = c.staff_seq WHERE c.branch_seq = #{branchSeq} AND c.time_slot_seq = #{slotSeq}
UNION ALL
/* 회원 */ SELECT c.seq AS classSeq, c.name AS className, c.capacity AS capacity, m.seq AS memberSeq, m.name AS name, m.phone_number AS phoneNumber, FALSE AS staff, CASE WHEN mm.status = '연기' THEN TRUE ELSE FALSE END AS postponed, CASE WHEN mm.status = '연기' THEN '△' ELSE '' END AS status, md.level AS level, m.info AS info, mm.start_date AS joinDate, mm.expiry_date AS expiryDate, mm.total_count AS totalCount, mm.used_count AS usedCount, ms.name AS membershipName FROM complex_member_class_mapping mcm JOIN complex_classes c ON c.seq = mcm.class_seq JOIN complex_members m ON m.seq = mcm.member_seq LEFT JOIN complex_member_metadata md ON md.member_seq = m.seq LEFT JOIN complex_member_memberships mm ON mm.member_seq = m.seq AND mm.status IN ('활성', '연기') AND mm.internal = FALSE LEFT JOIN memberships ms ON ms.seq = mm.membership_seq WHERE c.branch_seq = #{branchSeq} AND c.time_slot_seq = #{slotSeq}
ORDER BY classSeq, staff DESC, name

SELECT COUNT(*)
FROM complex_member_attendance a
JOIN complex_classes c             ON c.seq = a.class_seq
WHERE a.member_seq = #{memberSeq}
  AND c.branch_seq  = #{branchSeq}

SELECT COUNT(*)
FROM complex_member_attendance a
JOIN complex_classes c ON c.seq = a.class_seq
WHERE a.member_seq = #{staffSeq}
  AND c.branch_seq = #{branchSeq}
